options.customCss:
:root {
  /* Colors – Céu azul com nuvens (só azul + branco) */
  --chat--color-primary: #2196f3;                  /* Azul céu principal */
  --chat--color-primary-shade-50: #1e88e5;
  --chat--color-primary-shade-100: #1565c0;
  --chat--color-secondary: #90caf9;                /* Azul clarinho de nuvem */
  --chat--color-secondary-shade-50: #64b5f6;
  --chat--color-white: #ffffff;
  --chat--color-light: #f5f9ff;                    /* Quase branco, levemente azulado */
  --chat--color-light-shade-50: #e3f2fd;
  --chat--color-light-shade-100: #bbdefb;
  --chat--color-medium: #c5d5ea;
  --chat--color-dark: #102a43;                     /* Azul escuro para textos */
  --chat--color-disabled: #7d8591;
  --chat--color-typing: #404040;

  /* Base Layout */
  --chat--spacing: 1rem;
  --chat--border-radius: 0.9rem;
  --chat--transition-duration: 0.2s;
  --chat--font-family: (
    -apple-system,
    BlinkMacSystemFont,
    'Segoe UI',
    Roboto,
    Oxygen-Sans,
    Ubuntu,
    Cantarell,
    'Helvetica Neue',
    sans-serif
  );

  /* Window Dimensions */
  --chat--window--width: 400px;
  --chat--window--height: 600px;
  --chat--window--bottom: var(--chat--spacing);
  --chat--window--right: var(--chat--spacing);
  --chat--window--z-index: 9999;
  --chat--window--border: none;
  --chat--window--border-radius: 1.25rem;
  --chat--window--margin-bottom: var(--chat--spacing);

  /* Header Styles – céu azul suave */
  --chat--header-height: auto;
  --chat--header--padding: var(--chat--spacing);
  --chat--header--background: linear-gradient(
    135deg,
    #2196f3 0%,
    #64b5f6 40%,
    #bbdefb 100%
  );
  --chat--header--color: var(--chat--color-white);
  --chat--header--border-top: none;
  --chat--header--border-bottom: none;
  --chat--header--border-left: none;
  --chat--header--border-right: none;
  --chat--heading--font-size: 1.6em;
  --chat--subtitle--font-size: 0.95rem;
  --chat--subtitle--line-height: 1.6;

  /* Message Styles */
